import java.util.ArrayList;

public int maxWordsInSentence(ArrayList<String> sentences) {
    int maxWords = 0;
    for (String sentence : sentences) {
        String[] words = sentence.split(" ");
        maxWords = Math.max(maxWords, words.length);
    }
    return maxWords;
}
